class Solution {
    public int maximumCostSubstring(String s, String chars, int[] vals) {
        int maxCost = 0;
        for (int i = 0; i < s.length(); i++) {
            for (int j = i; j < s.length(); j++) {
                int cost = 0;
                for (int k = i; k <= j; k++) {
                    char c = s.charAt(k);
                    if (chars.indexOf(c) != -1) {
                        cost += vals[chars.indexOf(c)];
                    } else {
                        cost += c - 'a' + 1;
                    }
                }
                maxCost = Math.max(maxCost, cost);
            }
        }
        return maxCost;
    }
}
